commands.cmd:
mnt=$(findmnt --json -o TARGET,SOURCE,FSTYPE,OPTIONS) || { echo "findmnt failed" >&2; exit 1; }
printf '%s' "$mnt" | jq -c '
  [ .. | .filesystems? // empty | .[] ]
  | map(select(.fstype | test("^(proc|sysfs|cgroup|cgroup2|tmpfs|devtmpfs|devpts|mqueue|debugfs|tracefs|securityfs|pstore|bpf|configfs|fusectl|overlay|squashfs|autofs|binfmt_misc|hugetlbfs|nsfs|ramfs)$") | not))
  | {
      results: map({
        target: .target,
        source: (.source // ""),
        fstype: .fstype,
        read_only: ((.options | split(",")) | any(. == "ro"))
      })
    }
' || { echo "jq failed" >&2; exit 1; }
